    {{{ oval_metadata("Audit rules should capture information about session initiation.") }}}


{{% for audit_type in ["auditctl", "augenrules"] %}}



{{% for basename in ["utmp", "btmp", "wtmp"] %}}
{{% if audit_watches_style == "modern" %}}
{{% for arch in ["b32", "b64"] %}}

