{{% macro test_arse(filename, audit_type, arch="") %}}
{{% set basename = filename.split("/")[-1] %}}
{{% if audit_watches_style == "modern" %}}
{{% set id_part = basename + "_" + audit_type + "_" + arch %}}
{{% else %}}
{{% set id_part = basename + "_" + audit_type %}}
{{% endif %}}




{{% if audit_type == "augenrules" %}}
    ^/etc/audit/rules\.d/.*\.rules$
{{% elif audit_type == "auditctl" %}}
    /etc/audit/audit.rules
{{% endif %}}
{{% if audit_watches_style == "modern" %}}
    ^\-a\s+always,exit\s+\-F\s+arch={{{ arch }}}\s+\-F\s+path={{{ filename }}}\s+\-F\s+perm=\b([rx]*w[rx]*a[rx]*|[rx]*a[rx]*w[rx]*)\b.*$
{{% else %}}
    ^\-w\s+{{{ filename }}}\s+\-p\s+wa\b.*$
{{% endif %}}
    1

{{% endmacro %}}

{{% for filename in ["/var/run/utmp", "/var/log/btmp", "/var/log/wtmp"] %}}
{{% for audit_type in ["auditctl", "augenrules"] %}}
{{% if audit_watches_style == "modern" %}}
{{% for arch in ["b32", "b64"] %}}
{{{ test_arse(filename, audit_type, arch) }}}
{{% endfor %}}
{{% else %}}
{{{ test_arse(filename, audit_type) }}}
{{% endif %}}
{{% endfor %}}
{{% endfor %}}
